29	// ── Write serialization queue ─────────────────────────────────────────────────
30	// bun:sqlite Database is not concurrent-safe for writes. All write operations
31	// must be serialized through this queue to avoid "database is locked" errors.
32	
33	let _writeQueue: Promise<unknown> = Promise.resolve();
