35	export function serializeWrite<T>(fn: () => T | Promise<T>): Promise<T> {
36	  const next = _writeQueue.then(() => fn());
37	  // Swallow errors in the queue chain so one failure doesn't block subsequent writes
38	  _writeQueue = next.catch(() => {});
39	  return next;
40	}
