504	  }
505	
506	  // B5.1: 白名单管理 API（供 UI Capture Targets 页使用）
507	  if (path === "/api/proxy/whitelist" && req.method === "GET") {
508	    const { existsSync, readFileSync } = await import("node:fs");
509	    let hosts: string[] = [];
510	    if (existsSync(PROXY_PATHS.mitmHostsFile)) {
511	      try {
512	        const raw = JSON.parse(readFileSync(PROXY_PATHS.mitmHostsFile, "utf8"));
513	        if (Array.isArray(raw.hosts)) hosts = raw.hosts;
514	      } catch {}
515	    }
516	    return json({ hosts: ["api.anthropic.com", ...hosts], base: ["api.anthropic.com"], user: hosts });
517	  }
518	
519	  if (path === "/api/proxy/whitelist" && (req.method === "POST" || req.method === "PUT")) {
520	    const body = await req.json().catch(() => null);
521	    if (!body || !Array.isArray(body.hosts)) return json({ error: "invalid body" }, 400);
522	    const { mkdirSync, writeFileSync } = await import("node:fs");
523	    mkdirSync(PROXY_PATHS.home, { recursive: true, mode: 0o700 });
524	    const userHosts = (body.hosts as string[]).filter((h) => h !== "api.anthropic.com");
525	    writeFileSync(PROXY_PATHS.mitmHostsFile, JSON.stringify({ hosts: userHosts }, null, 2) + "\n");
526	    return json({ ok: true, hosts: userHosts });
527	  }
528	
529	  // ── Proxy 安装管理 API ────────────────────────────────────────────────────────
530	
531	  // 查询当前安装状态（preflight + daemon health + settings 检测）
532	  if (path === "/api/proxy/setup/status" && req.method === "GET") {
533	    return json(await getManagedProxyStatus());
534	  }
535	
536	  // 读取 settings.json env 块的辅助函数（供 install/start/uninstall 子进程继承）
537	  const loadSettingsEnv = async (): Promise<Record<string, string>> => {
538	    return readClaudeSettingsEnv();
539	  };
540	
541	  // 执行安装（dry-run 可选）
542	  if (path === "/api/proxy/setup/install" && req.method === "POST") {
543	    const body = await req.json().catch(() => ({})) as Record<string, unknown>;
544	    const dryRun = body.dryRun === true;
545	    const { spawn } = await import("node:child_process");
546	    const { join } = await import("node:path");
547	
548	    const scriptPath = join(import.meta.dir, "proxy/cli/install.ts");
549	    const args = ["run", scriptPath];
550	    if (dryRun) args.push("--dry-run");
551	
552	    // 合并 settings.json env，让安装器能看到用户已有的代理配置
553	    const settingsEnv = await loadSettingsEnv();
554	    const childEnv = { ...settingsEnv, ...process.env };
555	
556	    const result = await new Promise<{ ok: boolean; output: string }>((resolve) => {
557	      const child = spawn("bun", args, { env: childEnv, stdio: ["ignore", "pipe", "pipe"] }) as any;
558	      let out = "";
559	      child.stdout?.on("data", (d: Buffer) => (out += d.toString()));
560	      child.stderr?.on("data", (d: Buffer) => (out += d.toString()));
561	      child.on("close", (code: number) => resolve({ ok: code === 0, output: out }));
562	    });
563	    if (result.ok && !dryRun) {
564	      const started = await startManagedProxy();
565	      result.output += started.ok
566	        ? `\n[managed] proxy 已由 dashboard 托管启动，PID=${started.pid ?? "unknown"}\n`
567	        : `\n[managed] proxy 托管启动失败：${started.reason ?? "unknown"}\n`;
568	    }
569	    return json(result);
570	  }
571	
572	  // 执行卸载
573	  if (path === "/api/proxy/setup/uninstall" && req.method === "POST") {
574	    const { spawn } = await import("node:child_process");
575	    const { join } = await import("node:path");
576	
577	    await stopManagedProxy();
578	
579	    const scriptPath = join(import.meta.dir, "proxy/cli/uninstall.ts");
580	    const settingsEnv = await loadSettingsEnv();
581	    const childEnv = { ...settingsEnv, ...process.env };
582	
583	    const result = await new Promise<{ ok: boolean; output: string }>((resolve) => {
584	      const child = spawn("bun", ["run", scriptPath], { env: childEnv, stdio: ["ignore", "pipe", "pipe"] }) as any;
585	      let out = "";
586	      child.stdout?.on("data", (d: Buffer) => (out += d.toString()));
587	      child.stderr?.on("data", (d: Buffer) => (out += d.toString()));
588	      child.on("close", (code: number) => resolve({ ok: code === 0, output: out }));
589	    });
590	    return json(result);
591	  }
592	
593	  // 启动 dashboard 托管 proxy（仅构建 + 启动，不写 settings）
594	  if (path === "/api/proxy/setup/start" && req.method === "POST") {
595	    return json(await startManagedProxy());
596	  }
597	
598	  // 停止 dashboard 托管 proxy；如果发现旧版本遗留进程占用配置端口，也会尝试停止。
599	  if (path === "/api/proxy/setup/stop" && req.method === "POST") {
600	    return json(await stopManagedProxy());
601	  }
602	
603	  // 运行 preflight 检查（不写盘）
604	  // preflight 内部自动读取 managed / settings / shell 三层，无需在此合并。
605	  if (path === "/api/proxy/setup/preflight" && req.method === "GET") {
606	    const { runPreflight } = await import("./proxy/preflight");
607	    const portArg = Number(q.get("port") ?? process.env.API_DASHBOARD_PROXY_PORT ?? 38421);
608	    const report = await runPreflight({ ourPort: portArg });
609	    return json(report);
610	  }
611	
612	  return null; // not handled
613	}
