31	export async function parseClaudeSession(filePath: string): Promise<ParseResult> {
32	  const text = await Bun.file(filePath).text();
33	  const lines = text.trim().split("\n").filter(Boolean);
34	
35	  // Derive session ID from filename (stem)
36	  const sessionId = filePath.split("/").pop()!.replace(/\.jsonl$/, "");
37	
38	  // Derive project from parent directory name
39	  const parts = filePath.split("/");
40	  const projectHash = parts[parts.length - 2] ?? "unknown";
41	  // Try to find a human-readable project name from the hash directory
42	  // Claude stores project dirs as URL-encoded paths like "-Users-foo-bar"
43	  const project = projectHash.replace(/^-/, "").replace(/-/g, "/").replace(/^Users\/[^/]+\//, "");
44	
45	  let cwd = "";
46	  let model = "";
47	  let startedAt = "";
48	  let endedAt = "";
49	  let inputTokens = 0;
50	  let outputTokens = 0;
51	  let cacheCreationTokens = 0;
52	  let cacheReadTokens = 0;
53	  let toolCallCount = 0;
54	  const toolCallNames: Record<string, number> = {};
55	  const turns: Turn[] = [];
56	  let turnIndex = 0;
57	
58	  for (const line of lines) {
59	    let rec: any;
60	    try {
61	      rec = JSON.parse(line);
62	    } catch {
63	      continue;
64	    }
65	
66	    // Skip meta records
67	    if (rec.isMeta) continue;
68	    // Skip sidechain records
69	    if (rec.isSidechain) continue;
70	
71	    const ts: string = rec.timestamp ?? rec.ts ?? "";
72	    if (ts && !startedAt) startedAt = ts;
73	    if (ts) endedAt = ts;
74	
75	    if (rec.type === "user") {
76	      const msg = rec.message;
77	      if (!msg) continue;
