7	// 路径固定为 ~/.api-dashboard/proxy，不随 worktree 的 API_DASHBOARD_DIR 变化。
8	// 原因：不可能并发开发多个 proxy 实例；路径随 worktree 变只会造成路径不一致的 bug。
9	import { homedir } from "node:os";
